"<div>\n<i class=\"NoteType\">\n\u0426\u0438\u0442\u0430\u0442\u0430\n</i>\n<div class=\"grampsstylednote\">\n<p>\n\u21164 \u041c\u0430\u0439 12<br />\n\u041f\u043e\u0442\u043e\u043c\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u0434\u0432\u043e\u0440\u044f\u043d\u0438\u043d, \u0441\u044b\u043d \u0441\u0442\u0430\u0442\u0441\u043a\u043e\u0433\u043e \u0441\u043e\u0432\u0435\u0442\u043d\u0438\u043a\u0430 <strong>\u0418\u0432\u0430\u043d-\u0412\u0438\u043a\u0442\u043e\u0440 \u0410\u0434\u043e\u043b\u044c\u0444\u043e\u0432\u0438\u0447-\u0410\u0432\u0440\u0435\u043b\u044c\u044f\u043d\u043e\u0432\u0438\u0447-\u0410\u043d\u0442\u043e\u043d\u043e\u0432\u0438\u0447 \u0420\u0430\u0434\u0437\u0438\u043c\u0438\u043d\u0441\u043a\u0438\u0439-\u0424\u0440\u0430\u043d\u043a\u0435\u0432\u0438\u0447</strong>, \u0420\u0438\u043c\u0441\u043a\u043e-\u041a\u0430\u0442\u043e\u043b\u0438\u0447\u0435\u0441\u043a\u0430\u0433\u043e \u0432\u0435\u0440\u043e\u0438\u0441\u043f\u043e\u0432\u0435\u0434\u0430\u043d\u0438\u044f, \u043f\u0435\u0440\u0432\u044b\u043c \u0431\u0440\u0430\u043a\u043e\u043c<br />\n\u043b\u0435\u0442 24<br />\n\u0414\u043e\u0447\u044c \u041a\u043e\u043b\u043b\u0435\u0436\u0441\u043a\u0430\u0433\u043e \u0421\u043e\u0432\u0435\u0442\u043d\u0438\u043a\u0430, \u0434\u0435\u0432\u0438\u0446\u0430 <strong>\u041b\u0438\u0434\u0438\u044f \u0418\u0432\u0430\u043d\u043e\u0432\u043d\u0430 \u041c\u0438\u043d\u043a\u0435\u0432\u0438\u0447</strong> \u043f\u0440\u0430\u0432\u043e\u0441\u043b\u0430\u0432\u043d\u0430\u0433\u043e \u0432\u0435\u0440\u043e\u0438\u0441\u043f\u0432\u0435\u0434\u0430\u043d\u0438\u044f \u043f\u0435\u0440\u0432\u044b\u043c \u0431\u0440\u0430\u043a\u043e\u043c<br />\n\u043b\u0435\u0442 24<br />\n\u0441\u043e\u0432\u0435\u0440\u0448\u0438\u043b \u0442\u0430\u0438\u043d\u0441\u0442\u0432\u043e: \u041f\u0440\u043e\u0442\u043e\u0438\u0435\u0440\u0435\u0439 <strong>\u041c\u0438\u0445\u0430\u0438\u043b \u0422\u0440\u043e\u0438\u0446\u043a\u0438\u0439</strong> \u0441 \u043f\u0441\u0430\u043b\u043e\u043c\u0449\u0438\u043a\u043b\u043e\u043c <strong>\u0418\u043e\u0430\u043d\u043d\u043e\u043c \u041a\u0430\u0434\u043d\u0438\u043a\u043e\u0432\u044b\u043c</strong><br />\n\u041f\u043e\u0440\u0443\u0447\u0438\u0442\u0435\u043b\u0438<br />\n\u041f\u043e \u0436\u0435\u043d\u0438\u0445\u0435: \u0421\u0442\u0443\u0434\u0435\u043d\u0442 \u041f\u043e\u043b\u0438\u0442\u0435\u0445\u043d\u0438\u0447\u0435\u0441\u043a\u0430\u0433\u043e \u0418\u043d\u0441\u0442\u0438\u0442\u0443\u0442\u0430 \u0418\u043c\u043f\u0435\u0440\u0430\u0442\u043e\u0440\u0430 \u041f\u0435\u0442\u0440\u0430 \u0412\u0435\u043b\u0438\u043a\u0430\u0433\u043e, \u0418\u043d\u0436\u0435\u043d\u0435\u043d\u0440\u043d\u043e-\u0421\u0442\u0440\u043e\u0438\u0442\u0435\u043b\u044c\u043d\u0430\u0433\u043e \u043e\u0442\u0434\u0435\u043b\u0435\u043d\u0438\u044f <strong>\u0412\u043b\u0430\u0434\u0438\u043c\u0438\u0440 \u041d\u0438\u043a\u043e\u043b\u0430\u0435\u0432\u0438\u0447 \u0415\u0440\u0430\u0441\u043e\u0432</strong>. \u041a\u0430\u043d\u0446\u0435\u043b\u044f\u0440\u0441\u043a\u0438\u0439 \u0447\u0438\u043d\u043e\u0432\u043d\u0438\u043a \u043a\u0430\u043d\u0446\u0435\u043b\u044f\u0440\u0438\u0438 \u041c\u0438\u043d\u0438\u0441\u0442\u0440\u0430 \u041f\u0443\u0442\u0435\u0439 \u0421\u043e\u043e\u0431\u0449\u0435\u043d\u0438\u044f <strong>\u0412\u0430\u0441\u0438\u043b\u0438\u0439 \u0410\u043b\u0435\u043a\u0441\u0430\u043d\u0434\u0440\u043e\u0432\u0438\u0447 \u0410\u0440\u0445\u0438\u043f\u043e\u0432</strong><br />\n\u041f\u043e \u043d\u0435\u0432\u0435\u0441\u0442\u0435: \u0413\u0435\u043d\u0435\u0440\u0430\u043b-\u041b\u0435\u0439\u0442\u0435\u043d\u0430\u043d\u0442 <strong>\u041f\u0430\u0432\u0435\u043b \u041c\u0438\u0445\u0430\u0439\u043b\u043e\u0432\u0438\u0447 \u041b\u0438\u0441\u0435\u0432\u0438\u0447</strong>. \u041c\u0435\u0445\u0430\u043d\u0438\u043a \u0438\u0437 \u043c\u0435\u0449\u0430\u043d \u0433\u043e\u0440\u043e\u0434\u0430 \u041f\u0435\u0442\u0435\u0440\u0433\u043e\u0444\u0430 <strong>\u0410\u043b\u0435\u043a\u0441\u0435\u0439 \u0412\u0430\u0441\u0438\u043b\u044c\u0435\u0432\u0438\u0447 \u041f\u043e\u0441\u043d\u043e\u0432</strong>.\n</p>\n<p>\n&nbsp;\n</p>\n<p>\n&nbsp;\n</p>\n</div>\n</div>",
